import { useEffect, useMemo, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { generatePath, useLocation, useNavigate } from 'react-router-dom';
import { Account } from '@domain/account';
import { useGetAccountDocuments } from '@state/accountDocuments';
import { useGetAccount } from '@state/accounts';
import { useGetAllBankAccounts } from '@state/bank_accounts/helpers';
import { useFeatureFlag } from '@state/featureFlags';
import { useGetOnboardingSurvey } from '@state/onboarding_survey';
import { snakeCaseToCamelCase } from '@state/utils';
import { StepNavigationLinkStatus } from '@ui/components/StepNavigation/StepNavigationLink';
import { useOrganizationApplicationStore } from '../OrganizationApplicationContext';

type Step = {
  path:
    | 'name_and_type'
    | 'category'
    | 'onboarding_survey'
    | 'support_profile'
    | 'legal_entity'
    | 'documentation'
    | 'connect_bank'
    | 'financial_authority'
    | 'nonprofit_attestation'
    | 'kyc_verification'
    | 'submit_application';
  status: StepNavigationLinkStatus;
  text: string;
};

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const resolvePath = (object: any) => (path: string) =>
  path.split('.').reduce((o, p) => (o ? o[p] : undefined), object);

const showCategoryStep = (account?: Account) =>
  !account ||
  ['501c3', 'k12', 'higher-education'].includes(account?.subCategory ?? '') ||
  ['political', 'church-ministry', 'vendor'].includes(account?.category ?? '');

const requiredFields = {
  category: ['subCategoryType'],
  financial_authority: ['signature.url'],
  legal_entity: ['taxid', 'name', 'establishedDate', 'description'],
  name_and_type: ['name', 'category'],
  nonprofit_attestation: ['signature501c4.url', 'title501c4'],
  onboarding_survey: ['howDidYouHearAboutAnedot', 'annualProcessingVolume'],
  support_profile: ['softDescriptor', 'phone', 'email'],
};

export const useSteps = () => {
  const navigate = useNavigate();
  const { currentAccount, refetch: refetchAccount } = useGetAccount(10000);
  const { bankAccounts } = useGetAllBankAccounts();
  const { currentOnboardingSurvey } = useGetOnboardingSurvey();
  const { accountDocuments } = useGetAccountDocuments();
  const { t } = useTranslation('organizationApplication', { keyPrefix: 'navigation' });
  const { showPendingStepsAsErrors } = useOrganizationApplicationStore();
  const showKYCVerification = useFeatureFlag('orgApplication.vendorKYC');
  const showNonProfitAttestation = useFeatureFlag('orgApplication.c4kyc');

  const { pathname } = useLocation();
  const [currentPath, setCurrentPath] = useState<string>('');

  const steps = useMemo<Step[]>(() => {
    const incompleteStatus = showPendingStepsAsErrors ? 'error' : 'pending';
    const showKYCVerificationStep = currentAccount?.category === 'vendor' && showKYCVerification;
    const showNonProfitAttestationStep =
      currentAccount?.subCategory === '501c4' &&
      currentAccount?.category === 'nonprofit' &&
      showNonProfitAttestation;

    const getStatus = (step: Step['path']) => {
      switch (step) {
        case 'name_and_type':
        case 'category':
        case 'legal_entity':
        case 'support_profile':
        case 'financial_authority':
        case 'nonprofit_attestation':
          return requiredFields[step].every(resolvePath(currentAccount))
            ? 'complete'
            : incompleteStatus;
        case 'onboarding_survey':
          return requiredFields[step].every(resolvePath(currentOnboardingSurvey))
            ? 'complete'
            : incompleteStatus;
        case 'documentation':
          return accountDocuments?.find(({ documentType }) => documentType === 'irs_cp_575')
            ? 'complete'
            : incompleteStatus;
        case 'connect_bank':
          return bankAccounts?.length ? 'complete' : incompleteStatus;
        case 'submit_application':
          return 'pending';
        default:
          return incompleteStatus;
      }
    };

    return [
      'name_and_type',
      showCategoryStep(currentAccount) && 'category',
      'onboarding_survey',
      'support_profile',
      'legal_entity',
      'documentation',
      'connect_bank',
      'financial_authority',
      showNonProfitAttestationStep && 'nonprofit_attestation',
      showKYCVerificationStep && 'kyc_verification',
      'submit_application',
    ]
      .filter(Boolean)
      .map((path) => ({
        path: path === 'name_and_type' ? '' : path,
        status: path === currentPath ? 'current' : getStatus(path as Step['path']),
        text: t(snakeCaseToCamelCase(path as string) as never),
      })) as Step[];
  }, [
    accountDocuments,
    currentAccount,
    currentOnboardingSurvey,
    showPendingStepsAsErrors,
    currentPath,
    bankAccounts,
    showKYCVerification,
    showNonProfitAttestation,
    t,
  ]);

  const navigateStep = (direction: 'next' | 'previous') => (newAccount?: Account) => {
    const currentIdx = steps.findIndex((step) => step.path === currentPath);
    const movementIdx = direction === 'next' ? currentIdx + 1 : currentIdx - 1;
    let updatedSteps = steps;
    refetchAccount();

    // We have to manually update the steps to match what the `newAccount` requires
    // since the steps don't re-render when this function is called
    if (newAccount) {
      const categoryStepExists = !!steps.find((step) => step.path === 'category');
      const shouldShowCategoryStep = showCategoryStep(newAccount);

      if (categoryStepExists && !shouldShowCategoryStep) {
        updatedSteps = updatedSteps.slice(0, 1).concat(updatedSteps.slice(2));
      }

      if (!categoryStepExists && shouldShowCategoryStep) {
        updatedSteps = updatedSteps
          .slice(0, 1)
          .concat({ path: 'category' } as Step)
          .concat(updatedSteps.slice(2));
      }
    }

    if (movementIdx > -1 && movementIdx < steps.length) {
      navigate(
        generatePath('/accounts/:accountId/application/:path', {
          accountId: (newAccount?.id || currentAccount?.id) ?? '',
          path: updatedSteps[movementIdx].path,
        })
      );
    }
  };

  useEffect(() => {
    setCurrentPath(pathname.split('/')[4] ?? '');
  }, [pathname]);

  return {
    navigateNextStep: navigateStep('next'),
    navigatePrevStep: navigateStep('previous'),
    steps,
  };
};
