export function NameAndType() {
  const { t } = useTranslation('organizationApplication', { keyPrefix: 'nameAndType' });
  const schema = useSchema({ displayNameRequired: t('displayName.required') });

  const { createAccount, createAccountIsLoading } = useCreateAccount();
  const { currentAccount, isLoading: getAccountIsLoading } = useGetAccount();
  const { isLoading: updateAccountIsLoading, updateAccount } = useUpdateAccount();

  const { navigateNextStep } = useSteps();

  if (getAccountIsLoading) {
    return <Loading />;
  }

  const initialValues = {
    category: currentAccount?.category || 'political',
    displayName: currentAccount?.displayName || '',
  };

  const createAccountWithRedirect = (values: typeof initialValues) => {
    createAccount({ ...values, name: values.displayName }, { onSuccess: navigateNextStep });
  };

  const updateAccountWithRedirect = (values: typeof initialValues) => {
    updateAccount({ updates: values }, { onSuccess: navigateNextStep });
  };

  const onSubmit = currentAccount ? updateAccountWithRedirect : createAccountWithRedirect;

  return (
    <ArchBackgroundLayout variant="lightGreenLaptop">
      <Flex direction="column" gap={4}>
        <hgroup>
          <Heading as="h1">{t('heading')}</Heading>
          <Paragraph as="h2">{t('subheading')}</Paragraph>
