  const { createOnboardingSurvey, createOnboardingSurveyIsLoading } = useCreateOnboardingSurvey({
    shouldShowToast: false,
  });

  const { currentOnboardingSurvey, currentOnboardingSurveyIsLoading } = useGetOnboardingSurvey();

  const { updateOnboardingSurvey, updateOnboardingSurveyIsLoading } = useUpdateOnboardingSurvey({
    shouldShowToast: false,
  });

  if (currentAccountIsLoading || currentOnboardingSurveyIsLoading) {
    return <Loading />;
  }

  const onError = () => {
    showToast({
      message: t('requests.onError'),
      variant: 'error',
