  };

  const createOnboardingSurveyWithRedirect = (survey: Partial<OnboardingSurvey>) => {
    createOnboardingSurvey(survey, {
      onError,
      onSuccess: () => navigateNextStep(),
    });
  };

  const updateOnboardingSurveyWithRedirect = (survey: Partial<OnboardingSurvey>) => {
    updateOnboardingSurvey(survey, {
      onError,
      onSuccess: () => navigateNextStep(),
    });
  };

  const onSubmit = (survey: Partial<OnboardingSurvey>) => {
    const modifiedSurvey: Partial<OnboardingSurvey> = {
