        survey.linkedFromWebsiteUrl && !survey.linkedFromWebsiteUrl.match(/^https?:\/\//)
          ? `http://${survey.linkedFromWebsiteUrl}`
          : survey.linkedFromWebsiteUrl,
    };
    if (currentOnboardingSurvey?.id) {
      updateOnboardingSurveyWithRedirect(modifiedSurvey);
    } else {
      createOnboardingSurveyWithRedirect(modifiedSurvey);
    }
  };

  const initialValues = {
    annualProcessingVolume: currentOnboardingSurvey?.annualProcessingVolume || '',
    consultantFriendOtherName: currentOnboardingSurvey?.consultantFriendOtherName || '',
