    useEmails: currentOnboardingSurvey?.useEmails || false,
    useInternal: currentOnboardingSurvey?.useInternal || false,
    useLinkFromWebsite: currentOnboardingSurvey?.useLinkFromWebsite || false,
    useSocialMedia: currentOnboardingSurvey?.useSocialMedia || false,
    whenWillWebsiteGoLive: currentOnboardingSurvey?.whenWillWebsiteGoLive || '',
  };

  const schema = getSchema(t);

  return (
