                    <RadioControl key="no" value="false">
                      <Label variant="bold">{t('financialAuthority.acceptanceRadio.no')}</Label>
                      <Meta>{t('financialAuthority.acceptanceRadio.noHelper')}</Meta>
                    </RadioControl>
                  </Stack>
                </RadioGroup>

                {isFinancialAuthority ? (
                  <AcceptanceForm accountSlug={activeAccount?.slug} onSubmit={accept} />
                ) : (
                  <InviteOwnerForm onSubmit={inviteOwner} />
                )}

                {isChangingOwner && isAlreadySigned && (
                  <Button
                    onClick={useCurrentOwner}
                    textDecoration="none"
                    variant="link"
                    w="fit-content"
                  >
                    {t('financialAuthority.alreadySigned.useCurrentOwner')}
                  </Button>
                )}
              </>
            )}
          </Flex>
        </Panel>

        {!showSignedAlready &&
          (isFinancialAuthority ? (
