  if (!currentAccount?.category) {
    return (
      <Box>
        <Trans
          components={{ hlink: <ChakraLink as={RouterLink} to=".." /> }}
          i18nKey="categoryCheck"
          t={t}
        />
      </Box>
    );
  }

  const documents = DOCUMENTS_BY_CATEGORY[currentAccount?.category];

  const irsLetterCP575 = getCurrentFile(accountDocuments, 'irs_cp_575');
  const irsW9 = getCurrentFile(accountDocuments, 'irs_w9');

  const schema = getSchema({
    hasIRSCP575: !!irsLetterCP575,
    hasIRSW9: !!irsW9,
    // TODO: needsIRSCP575: based on tincheck
    needsIRSW9: currentAccount?.category === 'vendor',
  });

  return (
    <>
      <hgroup>
        <Heading as="h1">{t('heading')}</Heading>
        <Paragraph as="h2">{currentAccount?.displayName}</Paragraph>
      </hgroup>
      <Form onSubmit={() => navigateNextStep()} schema={schema}>
        <Flex direction="column" gap={6}>
          <Panel p={6} variant="primary">
            <Flex direction="column" gap={6}>
              <Box>
                <Paragraph as="h3">{t('subheading')}</Paragraph>
                <Paragraph>{t('intro')}</Paragraph>
              </Box>
              {documents.map((documentType) => {
                const i18nKey = snakeToCamel(documentType);
                const isRequired = ['irs_w9', 'irs_cp_575'].includes(documentType);

                return (
                  <DocumentationUploader
                    currentFile={getCurrentFile(accountDocuments, documentType)}
                    description={t(`${i18nKey}.description` as Parameters<typeof t>[0])}
                    documentType={documentType}
                    isRequired={isRequired}
                    key={documentType}
                    label={t(`${i18nKey}.heading` as Parameters<typeof t>[0])}
                  />
                );
              })}
              <Paragraph>{t('footer')}</Paragraph>
            </Flex>
          </Panel>
          <StepFooter />
        </Flex>
      </Form>
    </>
  );
}
