import { useEffect, useMemo } from 'react';
import { useRollbar } from '@rollbar/react';
import { useQuery } from 'react-query';
import { Address, AddressType } from '@domain/address';
import { ApiClient } from '@service/anedot/client';
import { PaginatedResponse, PaginateMeta } from '@service/anedot/interfaces';
import { generateQueryKey, resourceKeys } from '@state/cacheHelper';
import { makeSearchParams } from '@utils';
import { checkDuplicateAddressTypes } from './checkDuplicateAddressTypes';

type GetAddressOptions = { types?: AddressType[] };

interface IProps {
  accountId?: string;
  options?: GetAddressOptions;
}

type IReturn = {
  addresses: Address[];
  isLoading: boolean;
  meta?: PaginateMeta;
};

const getAddressesUrl = (accountId: string, options?: { types?: string[] }) => {
  const params = makeSearchParams({ account_id: accountId });

  if (options?.types) {
    params.set('address_type', options.types.join(','));
  }

  return `/addresses?${params.toString()}`;
};

export const useGetAddresses = ({ accountId, options }: IProps): IReturn => {
  const rollbar = useRollbar();

  const url = getAddressesUrl(accountId as string, options);
  const hasAccountId = !!accountId && accountId !== '';

  const query = useQuery<PaginatedResponse<Address[]>, string>(
    generateQueryKey({ accountId, parameters: options, resourceKey: resourceKeys.addresses }),
    async () => new ApiClient().get<PaginatedResponse<Address[]>>(url),
    {
      enabled: hasAccountId,
      staleTime: Infinity,
    }
  );

  const addresses = useMemo(() => query.data?.data ?? [], [query.data]);

  useEffect(() => {
    if (accountId && addresses.length > 1) {
      checkDuplicateAddressTypes({ accountId, addresses, rollbar });
    }
  }, [accountId, addresses, rollbar]);

  return {
    addresses,
    isLoading: query.isLoading,
    meta: query.data?.meta,
  };
};
