import { EditIcon } from '@ui/assets/icons/EditIcon';
import { SplitBadge } from '@ui/components/Badge/SplitBadge';
import { Button, LinkButton } from '@ui/components/Button';
import { Loading } from '@ui/components/Loading';
import { Heading, Label, Paragraph } from '@ui/components/typography';
import { Contact } from './components/Contact';

type SummaryProps = {
  account?: Account;
};

export const Summary = ({ account }: SummaryProps) => {
  const { t: tCommon } = useTranslation();
  const { t } = useTranslation('admin');
  const navigate = useNavigate();

  const { addresses } = useGetAddresses({
    accountId: account?.id,
    options: {
      types: ['legal', 'physical', 'mailing', 'other'],
    },
  });

  const { data: accountConfiguration } = useGetAccountConfiguration(account?.id);

  const {
    billing: billingAddress,
    legal: legalAddress,
    mailing: mailingAddress,
    other: otherAddress,
    physical: physicalAddress,
    public: publicAddress,
  } = getAddressTypes(addresses, account);

  const nonActive = useMemo(
    () => ['pending', 'draft', 'declined'].includes(account?.status as string),
    [account?.status]
  );

  if (!account) {
    return <Loading />;
  }

  return (
    <Grid autoFlow="column" columnGap={6} templateColumns="3fr minmax(350px, 1fr)">
      <Flex
        bgColor="neutral.0"
        borderRadius="16px 16px 0 0"
        direction="column"
        p={4}
        rowGap={5}
        width="full"
      >
        <Flex
          bgColor="neutral.200"
          borderRadius={8}
          justifyContent={nonActive ? 'space-between' : 'flex-end'}
          px={4}
          py={2}
          width="full"
        >
          {nonActive && (
            <Button
              leftIcon={<ContactInfoIcon />}
              onClick={() => {
                navigate(`/accounts/${account.id}/application`);
              }}
              textStyle="labelMedium"
              variant="text"
            >
              {t('accounts.summary.viewApplication')}
            </Button>
          )}
          <LinkButton
            href={`/staff/accounts/${account.id}/notes`}
            leftIcon={<EditIcon />}
            textStyle="labelMedium"
            variant="text"
          >
            {t('accounts.notes')}
          </LinkButton>
        </Flex>
        <Flex direction="column" gap={6} px={6}>
          <Flex gap={2}>
            <SplitBadge
              leftContent={tCommon('accountId')}
              rightBadgeProps={{ background: 'green.500' }}
              rightContent={account?.id}
            />
            <SplitBadge
              leftContent={t('labels.autoDisbursement')}
              rightBadgeProps={{ background: account.autoDisbursement ? 'green.500' : 'red.500' }}
              rightContent={`${!!account?.autoDisbursement}`}
            />
          </Flex>
          <Flex gap={8} w="full">
            <Flex flex={1} gap={2}>
              <OrganizationLegalDetails account={account} legalAddress={legalAddress} />
            </Flex>
            <Flex flex={1}>
              <OrganizationPublicDetails
                account={account}
                directoryTooltip={t('accounts.summary.directoryTooltip')}
                publicAddress={publicAddress || otherAddress}
              />
            </Flex>
          </Flex>
          <Flex direction="column">
            <Label pb={2} variant="bold">
              {tCommon('mission')}
            </Label>
            <Paragraph>{account?.description}</Paragraph>
          </Flex>
          <OtherAddresses
            billingAddress={billingAddress}
            mailingAddress={mailingAddress}
            otherAddress={otherAddress}
            physicalAddress={physicalAddress}
          />
          <Flex gap={8}>
            <Flex flex={1}>
              <Contact
                contact={accountConfiguration?.principalOwnerContact}
                title={t('accounts.summary.principalOwnerContact')}
              />
            </Flex>
            <Flex flex={1}>
              <Contact
                contact={accountConfiguration?.primaryContact}
                title={t('accounts.summary.primaryContact')}
              />
            </Flex>
          </Flex>
          {account?.signature?.url && (
            <Image alt="signature" src={account?.signature?.url} width={300} />
          )}
        </Flex>
      </Flex>
      <Flex
        bgColor="neutral.0"
        borderRadius={16}
        direction="column"
        gap={8}
        minH={700}
        p={6}
        width="full"
      >
        <Contact
          contact={accountConfiguration?.donorContact}
          description={t('accounts.summary.donorContactDescription')}
          title={t('accounts.summary.donorContact')}
        />
        <Contact
          contact={accountConfiguration?.marketingContact}
          description={t('accounts.summary.marketingContactDescription')}
          title={t('accounts.summary.marketingContact')}
        />
        <Contact
          contact={accountConfiguration?.financeContact}
          description={t('accounts.summary.financeContactDescription')}
          title={t('accounts.summary.financeContact')}
        />
        <Flex direction="column" gap={2}>
          <Heading textStyle="H4Regular">Links</Heading>
          {account?.url && <Link href={account.url}>{tCommon('website')}</Link>}
          {account?.facebook && <Link href={account.facebook}>Facebook</Link>}
          {account?.instagram && <Link href={account.instagram}>Instagram</Link>}
          {account?.twitter && <Link href={account.twitter}>Twitter</Link>}
        </Flex>
      </Flex>
    </Grid>
  );
};
