import { Flex } from '@chakra-ui/react';
import { useTranslation } from 'react-i18next';
import { AccountUpdates, useGetAccount, useUpdateAccount } from '@state/accounts';
import { Loading } from '@ui/components/Loading';
import { Panel } from '@ui/components/Panel';
import { useToast } from '@ui/components/Toast';
import { Form } from '@ui/components/formControls/Form';
import { Heading, Paragraph } from '@ui/components/typography';
import { StepFooter } from '../StepFooter';
import { useSteps } from '../useSteps';
import { PartyAffiliation } from './PartyAffiliation';
import { SubCategoryType } from './SubCategoryType';
import { getSchema } from './schema';

export function Category() {
  const { t } = useTranslation('organizationApplication', { keyPrefix: 'category' });
  const { showToast } = useToast();

  const { navigateNextStep } = useSteps();

  const { currentAccount, isLoading } = useGetAccount();
  const { isLoading: isUpdatingAccount, updateAccount } = useUpdateAccount({
    shouldShowToast: false,
  });

  if (isLoading) {
    return <Loading />;
  }

  const onSubmit = (account: AccountUpdates) => {
    updateAccount(
      { updates: account },
      {
        onError: () => {
          showToast({
            message: t('requests.onError'),
            variant: 'error',
          });
        },
        onSuccess: navigateNextStep,
      }
    );
  };

  const isPolitical = currentAccount?.category === 'political';
  const initialValues = {
    politicalParty: currentAccount?.politicalParty,
    subCategoryType: currentAccount?.subCategoryType,
  };

  return (
    <>
      <hgroup>
        <Heading as="h1">{t('heading')}</Heading>
        <Paragraph as="h2">{currentAccount?.displayName}</Paragraph>
      </hgroup>
      <Form initialValues={initialValues} onSubmit={onSubmit} schema={getSchema(isPolitical)}>
        <Flex direction="column" gap={6}>
          <Panel p={6} variant="primary">
            <Flex direction="column" gap={6}>
              <Paragraph>{t('intro')}</Paragraph>
              <div>
                <SubCategoryType />
                {isPolitical && <PartyAffiliation />}
              </div>
            </Flex>
          </Panel>
          <StepFooter isLoading={isUpdatingAccount} />
        </Flex>
      </Form>
    </>
  );
}
