const isValidSubCategoryKey = (key: string): key is keyof typeof SUBCATEGORY_TYPES => {
  return key in SUBCATEGORY_TYPES;
};

// "Directory Name" is our term for rep name + state + district (if necessary) e.g. "John Smith (CA - 03)"
const getDirectoryName = ({
  district,
  name,
  selectedSubCategoryType,
  state,
}: {
  district?: string;
  name: string;
  selectedSubCategoryType: string;
  state?: string;
}) => {
  if (selectedSubCategoryType === 'federal_president_8651') {
    return `${name} (President)`;
  }

  if (selectedSubCategoryType === 'federal_senate_8651') {
    return `${name} (${state || '--'})`;
  }

  if (selectedSubCategoryType === 'federal_house_8651') {
    return `${name} (${state || '--'} - ${district || '--'})`;
  }

  return name;
};

