  useEffect(() => {
    if (typeof candidateName !== 'string' || candidateName.trim() === '') {
      setValue('candidateName', '', {
        shouldDirty: true,
        shouldTouch: false,
      });
      return;
    }

    setValue('candidateName', candidateName, {
      shouldDirty: true,
      shouldTouch: false,
