  const isCategoryType = ['church-ministry', 'vendor'].includes(currentAccount?.category as string);
  const subCategoryKey = isCategoryType ? 'category' : 'subCategory';
  const categoryOrSubCategory = currentAccount?.[subCategoryKey] || '';

  const label = t(`heading.${categoryOrSubCategory}` as Parameters<typeof t>[0]);

  const { showToast } = useToast();

  if (!isValidSubCategoryKey(categoryOrSubCategory)) {
    // this should never happen but makes typescript happy with the rest of this component
