/**
 * Clean params from a record
 *
 * Removes empty strings and null from a record
 */

export type ParamValue =
  | Date
  | Date[]
  | string
  | string[]
  | boolean
  | boolean[]
  | number
  | number[]
  | null
  | undefined;

export type Params = Record<string, ParamValue>;

export const cleanParams = <P extends Params>(record: P) =>
  Object.entries(record).reduce<Record<string, string>>((obj, [k, v]) => {
    // don't include keys with empty strings, null, or undefined
    if (v === '' || v === null || typeof v === 'undefined') {
      return obj;
    }

    if (Array.isArray(v)) {
      return {
        ...obj,
        [k]: v.map((vi) => (vi instanceof Date ? vi.toISOString() : vi.toString())).join(','),
      };
    } else {
      return {
        ...obj,
        [k]: v instanceof Date ? v.toISOString() : v.toString(),
      };
    }
  }, {});
