import { Flex, Grid } from '@chakra-ui/react';
import { compareDesc, parseISO } from 'date-fns';
import { useTranslation } from 'react-i18next';
import { Account } from '@domain/account';
import { Address } from '@domain/address';
import { Label, Paragraph } from '@ui/components/typography';
import { OrganizationLegalDetails } from './OrganizationLegalDetails';
import { OrganizationPublicDetails } from './OrganizationPublicDetails';
import { OtherAddresses } from './OtherAddresses';

type RecentAddresses = {
  billing?: Address;
  legal?: Address;
  mailing?: Address;
  other?: Address;
  physical?: Address;
  public?: Address;
  shipping?: Address;
};

type OrganizationInformationProps = {
  account?: Account;
  addresses: Address[];
  showTooltip?: boolean;
};

export const getMostRecentAddress = (address1: Address | undefined, address2: Address) =>
  !address1 || compareDesc(parseISO(address1.createdAt!), parseISO(address2.createdAt!)) > 0
    ? address2
    : address1;

export const getAddressTypes = (addresses: Address[], account?: Account) =>
  addresses.reduce<RecentAddresses>((acc, curr) => {
    acc[curr.addressType] = getMostRecentAddress(acc[curr.addressType], curr);
    if (curr.id === account?.publicAddressId) {
      acc.public = curr;
    }
    return acc;
  }, {});

export const OrganizationInformation = ({
  account,
  addresses,
  showTooltip = false,
}: OrganizationInformationProps) => {
  const { t } = useTranslation();

  const {
    billing: billingAddress,
    legal: legalAddress,
    mailing: mailingAddress,
    other: otherAddress,
    physical: physicalAddress,
    public: publicAddress,
  } = getAddressTypes(addresses, account);

  return (
    <Flex direction="column" gap={6}>
      <Grid gap={16} templateColumns="repeat(2, 1fr)">
        <OrganizationLegalDetails
          account={account}
          legalAddress={legalAddress}
          showTooltip={showTooltip}
        />
        <OrganizationPublicDetails
          account={account}
          publicAddress={publicAddress || otherAddress}
          showTooltip={showTooltip}
        />
      </Grid>
      <Flex direction="column">
        <Label variant="bold">{t('mission')}</Label>
        <Paragraph>{account?.description}</Paragraph>
      </Flex>
      <OtherAddresses
        billingAddress={billingAddress}
        mailingAddress={mailingAddress}
        otherAddress={otherAddress}
        physicalAddress={physicalAddress}
        showTooltip={showTooltip}
      />
    </Flex>
  );
};
