+  const shouldMarkMissing =
+    options?.isRequired && !(options?.isPresent ?? hasRenderableValue(value));
+
+  return {
+    label,
+    value,
+    isMissing: shouldMarkMissing,
+  };
+};
+
+const getStatusDisplay = (status: StepNavigationLinkStatus) => {
+  switch (status) {
+    case 'complete':
+      return { colorScheme: 'green', key: 'complete' };
+    case 'error':
+      return { colorScheme: 'red', key: 'error' };
+    case 'current':
+      return { colorScheme: 'blue', key: 'current' };
+    default:
+      return { colorScheme: 'orange', key: 'incomplete' };
